class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int less = 0, equal = 0, more = nums.length - 1;
        while (equal <= more) {
            if (nums[equal] < pivot) {
                int temp = nums[less];
                nums[less] = nums[equal];
                nums[equal] = temp;
                less++;
                equal++;
            } else if (nums[equal] > pivot) {
                int temp = nums[equal];
                nums[equal] = nums[more];
                nums[more] = temp;
                more--;
            } else {
                equal++;
            }
        }
        return nums;
    }
}
